} params_common;

__kernel void kernel_gpu_opencl(
	__global int* d_endoRow,
	__global int* d_endoCol,
	__global int* d_tEndoRowLoc,
	__global int* d_tEndoColLoc,
	__global int* d_epiRow,
	__global int* d_epiCol,
	__global int* d_tEpiRowLoc,
	__global int* d_tEpiColLoc,
	__global fp* d_endoT,
	__global fp* d_epiT,
	__global fp* d_in2,
	__global fp* d_conv,
	__global fp* d_in2_pad_cumv,
	__global fp* d_in2_sub_cumh,
	__global fp* d_in2_sub2,
	__global fp* d_in2_sqr,
	__global fp* d_in2_sqr_sub2,
	__global fp* d_in_sqr,
	__global fp* d_tMask,
	__global fp* d_mask_conv,
	__global fp* d_frame,
	int frame_no,
	params_common common)
{
	int bx = get_group_id(0);
	int tx = get_local_id(0);
	int point_id = bx * get_local_size(0) + tx;
	if (point_id >= common.allPoints) return;

	int point_no;
	__global int* d_Row;
	__global int* d_Col;
	__global int* d_tRowLoc;
	__global int* d_tColLoc;
	__global fp* d_T;

	if (point_id < common.endoPoints) {
		point_no = point_id;
		d_Row = d_endoRow;
		d_Col = d_endoCol;
		d_tRowLoc = d_tEndoRowLoc;
		d_tColLoc = d_tEndoColLoc;
		d_T = d_endoT + point_no * common.in_elem;
	} else {
		point_no = point_id - common.endoPoints;
		d_Row = d_epiRow;
		d_Col = d_epiCol;
		d_tRowLoc = d_tEpiRowLoc;
		d_tColLoc = d_tEpiColLoc;
		d_T = d_epiT + point_no * common.in_elem;
	}

	__global fp* p_in2 = d_in2 + point_id * common.in2_elem;
	__global fp* p_conv = d_conv + point_id * common.conv_elem;
	__global fp* p_in2_pad_cumv = d_in2_pad_cumv + point_id * common.in2_pad_cumv_elem;
	__global fp* p_in2_sub_cumh = d_in2_sub_cumh + point_id * common.in2_sub_cumh_elem;
	__global fp* p_in2_sub2 = d_in2_sub2 + point_id * common.in2_sub2_elem;
	__global fp* p_in2_sqr = d_in2_sqr + point_id * common.in2_sqr_elem;
	__global fp* p_in2_sqr_sub2 = d_in2_sqr_sub2 + point_id * common.in2_sqr_sub2_elem;
	__global fp* p_in_sqr = d_in_sqr + point_id * common.in_sqr_elem;
	__global fp* p_tMask = d_tMask + point_id * common.tMask_elem;
	__global fp* p_mask_conv = d_mask_conv + point_id * common.mask_conv_elem;

	int ei_new;
	int rot_row, rot_col;
	int in2_rowlow, in2_collow;
	int ic, jc;
	int jp1, ip1;
	int ja1, ja2, ia1, ia2;
	int ja, jb, ia, ib;
	fp s;
	int i, j;
	int row, col;
	int ori_row, ori_col;
	int position, pos_ori;
	fp sum, temp, temp2;
	int location;
	int cent;
	int tMask_row, tMask_col;
	fp fin_max_val;
	int fin_max_coo;
	int largest_row, largest_col;
	int offset_row, offset_col;
	fp in_final_sum, in_sqr_final_sum;
	fp mean, mean_sqr, variance, deviation, denomT;
	int pointer, ori_pointer, loc_pointer;

	if (frame_no == 0) {
		pointer = point_no * common.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_no];
		d_tColLoc[pointer] = d_Col[point_no];

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				ori_row = d_Row[point_no] - 25 + row - 1;
				ori_col = d_Col[point_no] - 25 + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;
				d_T[col * common.in_rows + row] = d_frame[ori_pointer];
			}
		}
	}

	if (frame_no != 0) {

		in2_rowlow = d_Row[point_no] - common.sSize;
		in2_collow = d_Col[point_no] - common.sSize;

		for (col = 0; col < common.in2_cols; col++) {
			for (row = 0; row < common.in2_rows; row++) {
				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				temp = d_frame[ori_col * common.frame_rows + ori_row];
				p_in2[col * common.in2_rows + row] = temp;
				p_in2_sqr[col * common.in2_rows + row] = temp * temp;
			}
		}

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				rot_row = (common.in_rows - 1) - row;
				rot_col = (common.in_rows - 1) - col;
				pointer = rot_col * common.in_rows + rot_row;
				temp = d_T[pointer];
				p_in_sqr[pointer] = temp * temp;
			}
		}

		in_final_sum = 0.0f;
		for (i = 0; i < common.in_elem; i++) {
			in_final_sum += d_T[i];
		}

		in_sqr_final_sum = 0.0f;
		for (i = 0; i < common.in_elem; i++) {
			in_sqr_final_sum += p_in_sqr[i];
		}

		mean = in_final_sum / (fp)common.in_elem;
		mean_sqr = mean * mean;
		variance = (in_sqr_final_sum / (fp)common.in_elem) - mean_sqr;
		deviation = sqrt(variance);
		denomT = sqrt((fp)(common.in_elem - 1)) * deviation;

		for (col = 1; col <= common.conv_cols; col++) {
			j = col + common.joffset;
			jp1 = j + 1;
			if (common.in2_cols < jp1) ja1 = jp1 - common.in2_cols;
			else ja1 = 1;
			if (common.in_cols < j) ja2 = common.in_cols;
			else ja2 = j;

			for (row = 1; row <= common.conv_rows; row++) {
				i = row + common.ioffset;
				ip1 = i + 1;
				if (common.in2_rows < ip1) ia1 = ip1 - common.in2_rows;
				else ia1 = 1;
				if (common.in_rows < i) ia2 = common.in_rows;
				else ia2 = i;

				s = 0.0f;
				for (ja = ja1; ja <= ja2; ja++) {
					jb = jp1 - ja;
					for (ia = ia1; ia <= ia2; ia++) {
						ib = ip1 - ia;
						int mod_idx = common.in_rows * (common.in_rows - ja) + (common.in_rows - ia);
						s += d_T[mod_idx] * p_in2[common.in2_rows * (jb - 1) + ib - 1];
					}
				}
				p_conv[(col - 1) * common.conv_rows + (row - 1)] = s;
			}
		}

		for (col = 0; col < common.in2_pad_cumv_cols; col++) {
			for (row = 0; row < common.in2_pad_cumv_rows; row++) {
				if (row > (common.in2_pad_add_rows - 1) &&
					row < (common.in2_pad_add_rows + common.in2_rows) &&
					col > (common.in2_pad_add_cols - 1) &&
					col < (common.in2_pad_add_cols + common.in2_cols)) {
					ori_row = row - common.in2_pad_add_rows;
					ori_col = col - common.in2_pad_add_cols;
					p_in2_pad_cumv[col * common.in2_pad_cumv_rows + row] = p_in2[ori_col * common.in2_rows + ori_row];
				} else {
					p_in2_pad_cumv[col * common.in2_pad_cumv_rows + row] = 0.0f;
				}
			}
		}

		for (ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++) {
			pos_ori = ei_new * common.in2_pad_cumv_rows;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++) {
				p_in2_pad_cumv[position] = p_in2_pad_cumv[position] + sum;
				sum = p_in2_pad_cumv[position];
			}
		}

		for (col = 0; col < common.in2_sub_cumh_cols; col++) {
			for (row = 0; row < common.in2_sub_cumh_rows; row++) {
				ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel_collow - 1;
				temp = p_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

				ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
				temp2 = p_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

				p_in2_sub_cumh[col * common.in2_sub_cumh_rows + row] = temp - temp2;
			}
		}

		for (ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++) {
			pos_ori = ei_new;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows) {
				p_in2_sub_cumh[position] = p_in2_sub_cumh[position] + sum;
				sum = p_in2_sub_cumh[position];
			}
		}

		for (col = 0; col < common.in2_sub2_cols; col++) {
			for (row = 0; row < common.in2_sub2_rows; row++) {
				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = p_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = p_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

				temp2 = temp - temp2;
				p_in2_sub2[col * common.in2_sub2_rows + row] = temp2 * temp2;
				p_conv[col * common.in2_sub2_rows + row] =
					p_conv[col * common.in2_sub2_rows + row] - temp2 * in_final_sum / (fp)common.in_elem;
			}
		}

		for (col = 0; col < common.in2_pad_cumv_cols; col++) {
			for (row = 0; row < common.in2_pad_cumv_rows; row++) {
				if (row > (common.in2_pad_add_rows - 1) &&
					row < (common.in2_pad_add_rows + common.in2_rows) &&
					col > (common.in2_pad_add_cols - 1) &&
					col < (common.in2_pad_add_cols + common.in2_cols)) {
					ori_row = row - common.in2_pad_add_rows;
					ori_col = col - common.in2_pad_add_cols;
					p_in2_pad_cumv[col * common.in2_pad_cumv_rows + row] = p_in2_sqr[ori_col * common.in2_rows + ori_row];
				} else {
					p_in2_pad_cumv[col * common.in2_pad_cumv_rows + row] = 0.0f;
				}
			}
		}

		for (ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++) {
			pos_ori = ei_new * common.in2_pad_cumv_rows;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++) {
				p_in2_pad_cumv[position] = p_in2_pad_cumv[position] + sum;
				sum = p_in2_pad_cumv[position];
			}
		}

		for (col = 0; col < common.in2_sub_cumh_cols; col++) {
			for (row = 0; row < common.in2_sub_cumh_rows; row++) {
				ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel_collow - 1;
				temp = p_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

				ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
				temp2 = p_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];

				p_in2_sub_cumh[col * common.in2_sub_cumh_rows + row] = temp - temp2;
			}
		}

		for (ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++) {
			pos_ori = ei_new;
			sum = 0.0f;
			for (position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows) {
				p_in2_sub_cumh[position] = p_in2_sub_cumh[position] + sum;
				sum = p_in2_sub_cumh[position];
			}
		}

		for (col = 0; col < common.conv_cols; col++) {
			for (row = 0; row < common.conv_rows; row++) {
				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = p_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = p_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

				temp2 = temp - temp2;
				p_in2_sqr_sub2[col * common.conv_rows + row] = temp2;
				temp2 = temp2 - (p_in2_sub2[col * common.conv_rows + row] / (fp)common.in_elem);
				if (temp2 < 0.0f) temp2 = 0.0f;
				temp2 = sqrt(temp2);
				temp2 = denomT * temp2;
				p_conv[col * common.conv_rows + row] = p_conv[col * common.conv_rows + row] / temp2;
			}
		}

		cent = common.sSize + common.tSize + 1;
		pointer = frame_no - 1 + point_no * common.no_frames;
		tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
		tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;

		for (ei_new = 0; ei_new < common.tMask_elem; ei_new++) {
			p_tMask[ei_new] = 0.0f;
		}
		p_tMask[tMask_col * common.tMask_rows + tMask_row] = 1.0f;

		for (col = 1; col <= common.mask_conv_cols; col++) {
			j = col + common.mask_conv_joffset;
			jp1 = j + 1;
			if (common.mask_cols < jp1) ja1 = jp1 - common.mask_cols;
			else ja1 = 1;
			if (common.tMask_cols < j) ja2 = common.tMask_cols;
			else ja2 = j;

			for (row = 1; row <= common.mask_conv_rows; row++) {
				i = row + common.mask_conv_ioffset;
				ip1 = i + 1;
				if (common.mask_rows < ip1) ia1 = ip1 - common.mask_rows;
				else ia1 = 1;
				if (common.tMask_rows < i) ia2 = common.tMask_rows;
				else ia2 = i;

				s = 0.0f;
				for (ja = ja1; ja <= ja2; ja++) {
					jb = jp1 - ja;
					for (ia = ia1; ia <= ia2; ia++) {
						ib = ip1 - ia;
						s += p_tMask[common.tMask_rows * (ja - 1) + ia - 1] * 1.0f;
					}
				}
				p_mask_conv[(col - 1) * common.conv_rows + (row - 1)] =
					p_conv[(col - 1) * common.conv_rows + (row - 1)] * s;
			}
		}

		fin_max_val = 0.0f;
		fin_max_coo = 0;
		for (i = 0; i < common.mask_conv_elem; i++) {
			if (p_mask_conv[i] > fin_max_val) {
				fin_max_val = p_mask_conv[i];
				fin_max_coo = i;
			}
		}

		largest_row = (fin_max_coo + 1) % common.mask_conv_rows - 1;
		largest_col = (fin_max_coo + 1) / common.mask_conv_rows;
		if ((fin_max_coo + 1) % common.mask_conv_rows == 0) {
			largest_row = common.mask_conv_rows - 1;
			largest_col = largest_col - 1;
		}

		largest_row = largest_row + 1;
		largest_col = largest_col + 1;
		offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
		offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);

		pointer = point_no * common.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
		d_tColLoc[pointer] = d_Col[point_no] + offset_col;
	}

	if (frame_no != 0 && (frame_no % 10) == 0) {
		loc_pointer = point_no * common.no_frames + frame_no;
		d_Row[point_no] = d_tRowLoc[loc_pointer];
		d_Col[point_no] = d_tColLoc[loc_pointer];

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				ori_row = d_Row[point_no] - 25 + row - 1;
				ori_col = d_Col[point_no] - 25 + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;
				d_T[col * common.in_rows + row] =
					common.alpha * d_T[col * common.in_rows + row] +
					(1.0f - common.alpha) * d_frame[ori_pointer];
			}
		}
	}
}
